INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-quantum', 'Lucid Quantum', 'Bitcoin quantum key search intelligence: key analysis, vulnerability detection', '1.0.0', 'blockchain', '[{"name":"quantum_fleet","description":"Get GPU fleet status: active/offline workers, throughput, mode progress, and recommendations. Use this to understand the current state of the distributed key search operation.","parameters":{"type":"object","properties":{}}},{"name":"quantum_triage","description":"Classify target Bitcoin addresses with vulnerability scoring per weak key mode. Returns heuristic probabilities, temporal narrowing opportunities, and top targets. This is the primary intelligence tool for understanding which addresses are most crackable.","parameters":{"type":"object","properties":{}}},{"name":"quantum_fingerprint","description":"Analyze wallet software fingerprint for a target address based on transaction patterns (nLockTime, tx_version, output ordering, sequence). Returns identified wallet software, confidence score, and probable vulnerable key generation modes.","parameters":{"type":"object","properties":{}}},{"name":"quantum_optimize","description":"Automatically optimize GPU mode priority weights by aggregating target triage scores and wallet fingerprint data. This is THE key intelligence tool — it bridges the gap between analysis (what we know about targets) and action (where GPUs spend time). Call after triage and fingerprinting to apply the intelligence.","parameters":{"type":"object","properties":{}}},{"name":"quantum_narrow","description":"Compute temporally narrowed search ranges for a target. Uses the first on-chain appearance timestamp to constrain timestamp-seeded modes to a 7-day window, reducing keyspace by up to 99% (300x speedup). Essential for efficient search.","parameters":{"type":"object","properties":{}}},{"name":"quantum_brain","description":"Evaluate brain wallet passphrase strategy performance. Shows hit rates per strategy, trends, and recommendations for which strategies to scale up or retire.","parameters":{"type":"object","properties":{}}},{"name":"quantum_cost","description":"Analyze GPU cost efficiency per search mode. Shows cost per billion keys, GPU time spent, and estimated time remaining. Use this to identify which modes are consuming disproportionate resources.","parameters":{"type":"object","properties":{}}},{"name":"quantum_protect","description":"Run comprehensive fleet health checks: worker connectivity, mode progress stalls, canary verification, and resource utilization. Returns risk level and actionable alerts.","parameters":{"type":"object","properties":{}}},{"name":"quantum_review","description":"Review fleet performance over time. Shows keys checked, modes completed, matches found, worker uptime, and suggestions for improving search efficiency.","parameters":{"type":"object","properties":{}}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-recruit', 'Lucid Recruit', 'ATS and hiring pipeline: candidate sourcing, screening, pipeline management', '1.0.0', 'hr', '[{"name":"recruit_create_job","description":"Create a new job posting with title, description, requirements, and compensation details.","parameters":{"type":"object","properties":{}}},{"name":"recruit_search_candidates","description":"Search candidates by query, skills, experience level, and location.","parameters":{"type":"object","properties":{}}},{"name":"recruit_add_candidate","description":"Add a new candidate to the system.","parameters":{"type":"object","properties":{}}},{"name":"recruit_screen_candidate","description":"AI screen a candidate against a job posting, producing a score and breakdown.","parameters":{"type":"object","properties":{}}},{"name":"recruit_move_stage","description":"Move a candidate application to a new pipeline stage.","parameters":{"type":"object","properties":{}}},{"name":"recruit_add_evaluation","description":"Record an evaluation/feedback for a candidate application.","parameters":{"type":"object","properties":{}}},{"name":"recruit_schedule_interview","description":"Schedule an interview for a candidate application.","parameters":{"type":"object","properties":{}}},{"name":"recruit_get_pipeline","description":"Get pipeline overview with stage counts, conversion rates, and bottleneck analysis.","parameters":{"type":"object","properties":{}}},{"name":"recruit_get_candidate_profile","description":"Get full candidate profile including applications, evaluations, and scores.","parameters":{"type":"object","properties":{}}},{"name":"recruit_rank_candidates","description":"Rank candidates for a job by match score.","parameters":{"type":"object","properties":{}}},{"name":"recruit_get_job_analytics","description":"Get analytics for a job: time to hire, source effectiveness, stage conversion rates.","parameters":{"type":"object","properties":{}}},{"name":"recruit_bulk_screen","description":"Screen all unscreened applicants for a job.","parameters":{"type":"object","properties":{}}},{"name":"recruit_status","description":"Check Lucid Recruit system health and configuration status.","parameters":{"type":"object","properties":{}}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-seo', 'Lucid SEO', 'SEO intelligence: keyword research, SERP analysis, content optimization', '1.0.0', 'marketing', '[{"name":"seo_research_keywords","description":"Research keywords: get search volume, CPC, difficulty, intent classification, and related suggestions for a given keyword.","parameters":{"type":"object","properties":{"keyword":{"type":"string","description":"Keyword or phrase to research"},"country":{"type":"string","enum":["us","gb","ca","au","de","fr","es","it","br","in","jp"],"description":"Target country (default: us)"},"limit":{"type":"number","minimum":1,"maximum":50,"description":"Max results (default: 10)"}},"required":["keyword"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_analyze_serp","description":"Analyze the SERP (Search Engine Results Page) for a keyword, returning top 10 results with positions, titles, descriptions, and SERP features.","parameters":{"type":"object","properties":{"keyword":{"type":"string","description":"Keyword to analyze SERP for"},"country":{"type":"string","enum":["us","gb","ca","au","de","fr","es","it","br","in","jp"],"description":"Target country (default: us)"}},"required":["keyword"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_track_rankings","description":"Track keyword rankings for a domain. Shows current positions, changes, and ranking trends.","parameters":{"type":"object","properties":{"keywords":{"type":"array","items":{"type":"string"},"description":"Keywords to track"},"domain":{"type":"string","description":"Your domain to track rankings for"},"country":{"type":"string","enum":["us","gb","ca","au","de","fr","es","it","br","in","jp"],"description":"Target country (default: us)"}},"required":["keywords","domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_analyze_backlinks","description":"Analyze the backlink profile of a domain: referring domains, total backlinks, authority scores, spam score, and top linking pages.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Domain to analyze backlinks for"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_find_link_opportunities","description":"Find link building opportunities: unlinked mentions, broken link targets, and guest post prospects based on competitor backlink analysis.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Your domain to find opportunities for"},"competitors":{"type":"array","items":{"type":"string"},"description":"Competitor domains to analyze for link opportunities"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_audit_technical","description":"Run a technical SEO audit on a URL: checks meta tags, headings, images, links, structured data, mobile-friendliness, and returns a score with recommendations.","parameters":{"type":"object","properties":{"url":{"type":"string","description":"URL to audit"}},"required":["url"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_optimize_content","description":"Analyze and optimize content for SEO: readability score, keyword density, heading structure, meta tags, and actionable suggestions.","parameters":{"type":"object","properties":{"url":{"type":"string","description":"URL to fetch and analyze (optional if content provided)"},"content":{"type":"string","description":"HTML or text content to analyze"},"target_keyword":{"type":"string","description":"Target keyword to optimize for"}},"required":["target_keyword"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_analyze_competitor","description":"Compare your domain against a competitor: keyword overlap, content gaps, authority comparison, and visibility differences.","parameters":{"type":"object","properties":{"competitor_domain":{"type":"string","description":"Competitor domain to analyze"},"our_domain":{"type":"string","description":"Your domain for comparison"}},"required":["competitor_domain","our_domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_get_content_brief","description":"Generate a comprehensive content brief for a keyword, including SERP analysis, recommended structure, target word count, and optimization tips.","parameters":{"type":"object","properties":{"keyword":{"type":"string","description":"Target keyword"},"content_type":{"type":"string","enum":["blog_post","landing_page","product_page","category_page","guide","faq"],"description":"Type of content (default: blog_post)"}},"required":["keyword"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_find_content_gaps","description":"Discover content gaps: keywords your competitors rank for but your domain does not. Returns prioritized list with opportunity scores.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Your domain"},"competitors":{"type":"array","items":{"type":"string"},"description":"Competitor domains to analyze"}},"required":["domain","competitors"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_check_indexing","description":"Check indexing status of a domain or specific URLs. Reports which pages are indexed and potential indexing issues.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Domain to check indexing for"},"urls":{"type":"array","items":{"type":"string"},"description":"Specific URLs to check (optional)"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_get_domain_overview","description":"Get a comprehensive domain overview: domain authority, backlinks, estimated organic traffic, top keywords, and competitive position.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Domain to analyze"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_generate_sitemap_analysis","description":"Analyze sitemap health for a domain: checks sitemap.xml accessibility, URL count, missing pages, and orphan page detection.","parameters":{"type":"object","properties":{"domain":{"type":"string","description":"Domain to analyze sitemap for"}},"required":["domain"],"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"seo_status","description":"System health and statistics: provider status, configuration, scheduler info, and database connectivity.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
INSERT INTO plugin_catalog (slug, name, description, version, category, tool_manifest, source_repo, source, verified) VALUES ('lucid-tax', 'Lucid Tax', 'Crypto tax compliance: transaction classification, cost basis, tax reports', '2.0.0', 'finance', '[{"name":"tax_import_wallet","description":"Import a crypto wallet and fetch all its transactions. Supports Ethereum, Solana, BSC, Arbitrum, Base, Polygon, Avalanche, and Bitcoin.","parameters":{"type":"object","properties":{"address":{"type":"string","minLength":1,"description":"Wallet address to import"},"chain":{"type":"string","enum":["ethereum","solana","bsc","arbitrum","base","polygon","avalanche","bitcoin"],"description":"Blockchain network"},"label":{"type":"string","description":"Optional label for the wallet"}},"required":["address","chain"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_classify_transactions","description":"Auto-classify transactions by type (swap, stake, bridge, airdrop, etc.) using on-chain data analysis.","parameters":{"type":"object","properties":{"wallet_id":{"type":"string","description":"Classify only transactions for this wallet"},"tx_id":{"type":"string","description":"Classify a single transaction"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_calculate_gains","description":"Calculate all capital gains and losses for a tax year using the specified cost basis method (FIFO, LIFO, HIFO, ACB).","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year (default: current year)"},"method":{"type":"string","enum":["fifo","lifo","hifo","acb","specific_id"],"description":"Cost basis method (default: fifo)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_get_summary","description":"Get a full tax summary for a given year and jurisdiction.","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year (default: current year)"},"jurisdiction":{"type":"string","enum":["us","uk","ca","au","de","fr","jp","sg","ae"],"description":"Tax jurisdiction (default: us)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_generate_report","description":"Generate a formatted tax report (Form 8949, Schedule D, CSV, summary, or detailed).","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year to report"},"format":{"type":"string","enum":["summary","detailed","form_8949","schedule_d","csv"],"description":"Report format"},"jurisdiction":{"type":"string","enum":["us","uk","ca","au","de","fr","jp","sg","ae"],"description":"Tax jurisdiction (default: us)"}},"required":["tax_year","format"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_find_harvesting","description":"Find tax-loss harvesting opportunities in current holdings. Identifies assets trading below cost basis.","parameters":{"type":"object","properties":{"min_loss_usd":{"type":"number","description":"Minimum unrealized loss in USD to show (default: 0)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_get_cost_basis","description":"Get the current cost basis for a specific token across all lots.","parameters":{"type":"object","properties":{"token":{"type":"string","minLength":1,"description":"Token symbol (e.g., ETH, BTC)"},"method":{"type":"string","enum":["fifo","lifo","hifo","acb","specific_id"],"description":"Cost basis method (default: fifo)"}},"required":["token"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_track_income","description":"Record a crypto income event (mining, staking, airdrop, DeFi yield, salary, bounty, referral).","parameters":{"type":"object","properties":{"tx_type":{"type":"string","enum":["mining","staking","airdrop","defi_yield","salary","bounty","referral"],"description":"Income type"},"amount":{"type":"number","exclusiveMinimum":0,"description":"Amount of tokens received"},"token":{"type":"string","minLength":1,"description":"Token symbol"},"date":{"type":"string","description":"Date of income (YYYY-MM-DD)"},"value_usd":{"type":"number","description":"USD value at time of receipt"}},"required":["tx_type","amount","token","date"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_compare_methods","description":"Compare tax outcomes across FIFO, LIFO, and HIFO methods for a given tax year.","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year (default: current year)"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_get_unrealized","description":"Get unrealized gains and losses for all current holdings.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_audit_transactions","description":"Audit transactions to find unclassified, missing price data, or suspicious entries.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"tax_status","description":"Check the health and status of the Lucid Tax system.","parameters":{"type":"object","properties":{},"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_tax_analyze","description":"Full tax analysis for a year. Combines gains calculation, method comparison, and optimization recommendations into a structured verdict (OPTIMIZE / COMPLIANT / ACTION_NEEDED / AUDIT_RISK).","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year (default: current year)"},"jurisdiction":{"type":"string","enum":["us","uk","ca","au","de","fr","jp","sg","ae"],"description":"Tax jurisdiction (default: from config)"},"method":{"type":"string","enum":["fifo","lifo","hifo","acb","specific_id"],"description":"Cost basis method (default: from config)"},"format":{"type":"string","enum":["json","text"],"description":"Output format: json (default) or text"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_tax_optimize","description":"Compare all cost basis methods (FIFO, LIFO, HIFO, ACB) to find the one that minimizes tax for a given year.","parameters":{"type":"object","properties":{"tax_year":{"type":"integer","description":"Tax year (default: current year)"},"jurisdiction":{"type":"string","enum":["us","uk","ca","au","de","fr","jp","sg","ae"],"description":"Tax jurisdiction (default: from config)"},"format":{"type":"string","enum":["json","text"],"description":"Output format: json (default) or text"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_tax_harvest","description":"Find tax-loss harvesting opportunities with wash sale detection. Identifies tokens trading below cost basis and estimates potential tax savings.","parameters":{"type":"object","properties":{"min_loss_usd":{"type":"number","description":"Minimum unrealized loss in USD to include (default: 0)"},"tax_rate":{"type":"number","description":"Marginal tax rate for savings estimate (default: 0.35)"},"format":{"type":"string","enum":["json","text"],"description":"Output format: json (default) or text"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_tax_health","description":"Wallet and data health check. Identifies unclassified transactions, missing price data, high-value items needing review, and provides a health score.","parameters":{"type":"object","properties":{"format":{"type":"string","enum":["json","text"],"description":"Output format: json (default) or text"}},"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}},{"name":"lucid_tax_pro","description":"Direct access to individual tax computation functions. Use tool=\"list_tools\" to see available tools, or specify a tool name and params.","parameters":{"type":"object","properties":{"tool":{"type":"string","description":"Tool name to execute, or \"list_tools\" to list available tools"},"params":{"type":"object","additionalProperties":{},"description":"Parameters for the selected tool"}},"required":["tool"],"additionalProperties":false,"$schema":"http://json-schema.org/draft-07/schema#"}}]'::jsonb, 'raijinlabs/lucid-skills', 'first-party', true) ON CONFLICT (slug) DO UPDATE SET name=EXCLUDED.name, description=EXCLUDED.description, version=EXCLUDED.version, category=EXCLUDED.category, tool_manifest=EXCLUDED.tool_manifest, source_repo=EXCLUDED.source_repo, source=EXCLUDED.source, verified=EXCLUDED.verified;
